const name = "小明", age = 20;
// 插值
`Hello, ${name}!`  // "Hello, 小明!"
// 表达式
`${name}今年${age}岁，${age >= 18 ? '成年' : '未成年'}`
// 多行
`<div>
  <h1>${name}</h1>
</div>`

// split — 拆分为数组
"a,b,c".split(",")   // ["a","b","c"]

// trim — 去首尾空白
"  hello  ".trim()   // "hello"

// padStart — 补零
"5".padStart(3, "0")  // "005"

// replace — 只替换第一个！
"a-b-c".replace("-", "_")    // "a_b-c"

// replaceAll — 替换所有 (ES2021)
"a-b-c".replaceAll("-", "_")  // "a_b_c"

// 正则 /g — 替换所有（兼容旧浏览器）
"a-b-c".replace(/-/g, "_")   // "a_b_c"

